package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
    }

    @Test
    public void testPrintCreatesCSVPrinterSuccessfully() throws Exception {
        // Mock CSVPrinter to avoid actual file IO
        CSVPrinter csvPrinterMock = mock(CSVPrinter.class);

        // Use a wrapper class to override print(File, Charset) method
        CSVFormat csvFormatWrapper = new CSVFormatWrapper(csvFormat, csvPrinterMock);

        CSVPrinter printer = csvFormatWrapper.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(csvPrinterMock, printer);
    }

    @Test
    public void testPrintThrowsIOExceptionWhenFileOutputStreamFails() {
        File nonWritableFile = new File("/root/forbiddenfile.csv");
        Charset charset = Charset.forName("UTF-8");

        assertThrows(IOException.class, () -> csvFormat.print(nonWritableFile, charset));
    }

    @Test
    public void testPrintThrowsNullPointerExceptionWhenFileIsNull() {
        assertThrows(NullPointerException.class, () -> csvFormat.print((File) null, charset));
    }

    @Test
    public void testPrintThrowsNullPointerExceptionWhenCharsetIsNull() {
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockFile, null));
    }

    // Wrapper class to override print method without subclassing final CSVFormat
    private static class CSVFormatWrapper extends CSVFormat {
        private final CSVFormat delegate;
        private final CSVPrinter printerMock;

        CSVFormatWrapper(CSVFormat delegate, CSVPrinter printerMock) {
            super(delegate.getDelimiter(),
                    delegate.getQuoteCharacter(),
                    delegate.getQuoteMode(),
                    delegate.getCommentMarker(),
                    delegate.getEscapeCharacter(),
                    delegate.getIgnoreSurroundingSpaces(),
                    delegate.getIgnoreEmptyLines(),
                    delegate.getRecordSeparator(),
                    delegate.getNullString(),
                    delegate.getHeaderComments(),
                    delegate.getHeader(),
                    delegate.getSkipHeaderRecord(),
                    delegate.getAllowMissingColumnNames(),
                    delegate.getIgnoreHeaderCase(),
                    delegate.getTrim(),
                    delegate.getTrailingDelimiter());
            this.delegate = delegate;
            this.printerMock = printerMock;
        }

        @Override
        public CSVPrinter print(final File out, Charset charset) throws IOException {
            return printerMock;
        }
    }
}
